.tile-value-lg {
  font-size: 18px;
  font-weight: 600;
}

.tile-value-md {
  font-size: 14px;
  font-weight: 600;
  color: #0f172a;
}

.tile-sub {
  font-size: 11px;
  color: #94a3b8;
  margin: 6px 0 0;
